            [${flyway:defaultSchema}].[RecordChange] c
        INNER JOIN
            CTE_RootParent p ON c.[ID] = p.[RestoredFromID]
        WHERE
            p.[Depth] < 100
    )
    SELECT TOP 1
        [RootParentID] AS RootID
    FROM
        CTE_RootParent
    WHERE
        [RestoredFromID] IS NULL
    ORDER BY
        [RootParentID]
);
